INSERT INTO document_chunks (id, document_id, chunk_index, content, token_count, content_hash, created_at) VALUES
  ('f0000000-0000-0000-0000-000000000001', 'e0000000-0000-0000-0000-000000000001', 0, '2026-05-05 킥오프 회의. 참석: 김희진(PM), 이성우(AI), 김예은(인프라), 김성호(백엔드), 박주원(프론트). 프로젝트명 OpsRadar로 확정. 8주 MVP 일정 합의. 기술스택: FastAPI + PostgreSQL + FAISS + React.', 82, 'seed-chunk-001', '2026-05-05 10:30:00+09'),
  ('f0000000-0000-0000-0000-000000000002', 'e0000000-0000-0000-0000-000000000001', 1, '1주차 주요 액션아이템: 김성호 - DB 스키마 설계 및 기본 API 껍데기 구현. 이성우 - RAG 파이프라인 설계 시작. 김예은 - Azure VM 및 PostgreSQL 환경 세팅. 박주원 - React 프로젝트 초기화 및 레이아웃 구성.', 70, 'seed-chunk-002', '2026-05-05 10:30:00+09'),
  ('f0000000-0000-0000-0000-000000000003', 'e0000000-0000-0000-0000-000000000002', 0, '김성호: documents API 엔드포인트 완성했습니다. POST /api/v1/documents/upload 동작 확인. 김희진: todos API도 이번 주 안에 껍데기라도 올려주세요. 김성호: 네 오늘 중으로 올리겠습니다.', 62, 'seed-chunk-003', '2026-05-12 14:30:00+09'),
  ('f0000000-0000-0000-0000-000000000004', 'e0000000-0000-0000-0000-000000000002', 1, '박주원: 프론트 레이아웃 완성. 사이드바 7개 메뉴 구현. 근데 API 명세서 기준으로 연동하면 되는거죠? 김희진: 맞아요 노션 API 명세서 참고하면 됩니다. 박주원: 확인했습니다. 업로드 UI부터 시작하겠습니다.', 69, 'seed-chunk-004', '2026-05-12 14:30:00+09'),
  ('f0000000-0000-0000-0000-000000000005', 'e0000000-0000-0000-0000-000000000003', 0, '2주차 회의 (2026-05-12). 진행상황: 백엔드 API 껍데기 완성(김성호), Azure VM 세팅 완료(김예은), 프론트 레이아웃 완성(박주원). 이슈: RAG 파이프라인 FAISS 연동 예상보다 복잡. 이성우 추가 시간 필요.', 77, 'seed-chunk-005', '2026-05-12 18:30:00+09'),
  ('f0000000-0000-0000-0000-000000000006', 'e0000000-0000-0000-0000-000000000004', 0, '이성우: FAISS 인덱스 저장/로드 구현 완료. 근데 Azure OpenAI API 타임아웃이 계속 발생합니다. 5초 이상 지연 케이스가 늘고 있어요. 김성호: 혹시 배치 사이즈 문제 아닐까요? 이성우: 확인해볼게요.', 71, 'seed-chunk-006', '2026-05-14 09:30:00+09'),
  ('f0000000-0000-0000-0000-000000000007', 'e0000000-0000-0000-0000-000000000004', 1, '이성우: RAG 검색 정확도가 예상보다 낮습니다. 청크 사이즈를 줄여봤는데도 관련 없는 결과가 섞여요. 임베딩 모델 교체를 고려해봐야 할 것 같습니다. 희진님 확인 부탁드려요.', 62, 'seed-chunk-007', '2026-05-14 09:30:00+09'),
  ('f0000000-0000-0000-0000-000000000008', 'e0000000-0000-0000-0000-000000000005', 0, '[이슈 로그 2026-05-14] Azure OpenAI API 응답 지연 5초 초과. 발생 빈도: 오전 기준 약 30%. 원인 추정: 토큰 한도 근접 또는 리전 부하. 담당: 이성우. 임시 조치: 재시도 로직 추가 필요.', 74, 'seed-chunk-008', '2026-05-14 11:30:00+09');
