INSERT INTO weekly_reports (id, project_id, created_by_member_id, week_start, week_end, content, progress_rate, created_at) VALUES
  ('50000000-0000-0000-0000-000000000001', 'c0000000-0000-0000-0000-000000000001', 'd0000000-0000-0000-0000-000000000001', '2026-05-05', '2026-05-09', '1주차 운영 보고서: 킥오프 완료, 기술스택 및 역할 확정, Azure VM PostgreSQL 환경 세팅 시작.', 20, '2026-05-09 18:00:00+09'),
  ('50000000-0000-0000-0000-000000000002', 'c0000000-0000-0000-0000-000000000001', 'd0000000-0000-0000-0000-000000000001', '2026-05-12', '2026-05-16', '2주차 운영 보고서: API 껍데기 완성, 프론트 레이아웃 완성, FAISS 인덱스 저장/로드 기본 구현. Azure OpenAI 타임아웃과 RAG 검색 정확도 이슈가 남아 있음.', 45, '2026-05-16 18:00:00+09');
INSERT INTO monthly_reports (id, project_id, created_by_member_id, month_start, month_end, content, progress_rate, created_at) VALUES
  ('51000000-0000-0000-0000-000000000001', 'c0000000-0000-0000-0000-000000000001', 'd0000000-0000-0000-0000-000000000001', '2026-05-01', '2026-05-31', '5월 월간 보고서 중간본: 환경 세팅, API 구조, 프론트 레이아웃 완료. Azure OpenAI 타임아웃과 RAG 정확도 개선 필요.', 45, '2026-05-14 18:00:00+09');
INSERT INTO handoff_reports (id, project_id, from_member_id, to_member_id, handoff_type, content, created_at) VALUES
  ('52000000-0000-0000-0000-000000000001', 'c0000000-0000-0000-0000-000000000001', 'd0000000-0000-0000-0000-000000000001', 'd0000000-0000-0000-0000-000000000004', 'handover', 'OpsRadar MVP 현황 인수인계: PostgreSQL + FAISS 환경 세팅, API 엔드포인트 껍데기, 프론트 사이드바와 업로드 UI가 완료됨. 남은 항목은 인증, Dashboard 집계 API, AI Assistant RAG 완성.', '2026-05-14 17:00:00+09');
INSERT INTO chat_messages (id, project_id, member_id, role, content, created_at) VALUES
  ('60000000-0000-0000-0000-000000000001', 'c0000000-0000-0000-0000-000000000001', 'd0000000-0000-0000-0000-000000000001', 'user', '현재 가장 위험한 이슈는?', '2026-05-14 13:00:00+09'),
  ('60000000-0000-0000-0000-000000000002', 'c0000000-0000-0000-0000-000000000001', NULL, 'assistant', '현재 High Risk 이슈는 2건입니다. Azure OpenAI API 타임아웃과 RAG 검색 정확도 문제가 가장 큽니다.', '2026-05-14 13:00:05+09'),
  ('60000000-0000-0000-0000-000000000003', 'c0000000-0000-0000-0000-000000000001', 'd0000000-0000-0000-0000-000000000001', 'user', '이번주 미완료 Todo 알려줘', '2026-05-14 13:01:00+09'),
  ('60000000-0000-0000-0000-000000000004', 'c0000000-0000-0000-0000-000000000001', NULL, 'assistant', '이번 주 미완료 Todo는 Azure timeout 재시도 로직, RAG 정확도 개선, todos API 로직 구현, 3주차 미팅 자료 준비입니다.', '2026-05-14 13:01:05+09');
INSERT INTO ai_summaries (id, document_id, project_id, source_faiss_index_id, todo_count, issue_count, blocked_count, summary, created_at) VALUES
  ('70000000-0000-0000-0000-000000000001', 'e0000000-0000-0000-0000-000000000003', 'c0000000-0000-0000-0000-000000000001', '10000000-0000-0000-0000-000000000001', 3, 2, 1, '2주차 운영 요약: API 껍데기 전체 완성, 프론트 레이아웃 완성. Azure OpenAI 타임아웃과 RAG 검색 정확도 이슈가 High로 남아 있음.', '2026-05-12 19:00:00+09'),
  ('70000000-0000-0000-0000-000000000002', 'e0000000-0000-0000-0000-000000000005', 'c0000000-0000-0000-0000-000000000001', '10000000-0000-0000-0000-000000000001', 2, 1, 0, 'Azure OpenAI API 타임아웃 이슈 분석: 오전 기준 약 30% 발생. 재시도 로직 추가 및 배치 사이즈 조정 권고.', '2026-05-14 12:00:00+09');
